def setup_environment_variables(config_dir):
    """Set up environment variables for the package."""
    env_vars = ENV_VARS.copy()
    env_vars["INTERNAL_TOOLKIT_HOME"] = str(config_dir)
    env_vars["INTERNAL_TOOLKIT_CONFIG"] = str(config_dir / "config" / "settings.json")

    print("[Setup] Setting up environment variables...")

    # Set environment variables for the current process
    for key, value in env_vars.items():
        os.environ[key] = value
        print(f"[Setup]   {key}={value}")

    # Write environment variables to a shell-sourceable file
    env_file = config_dir / "env.sh"
    with open(env_file, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Environment variables for {PACKAGE_NAME}\n")
        f.write(f"# Generated during installation - version {PACKAGE_VERSION}\n")
        f.write(f"# Source this file: source {env_file}\n\n")
        for key, value in env_vars.items():
            f.write(f'export {key}="{value}"\n')

    print(f"[Setup]   Environment file written to: {env_file}")

    # Also write a .env file for tools that support dotenv
    dotenv_file = config_dir / ".env"
    with open(dotenv_file, "w") as f:
        f.write(f"# Environment variables for {PACKAGE_NAME}\n")
        f.write(f"# Version: {PACKAGE_VERSION}\n\n")
        for key, value in env_vars.items():
            f.write(f"{key}={value}\n")

    print(f"[Setup]   .env file written to: {dotenv_file}")

    # Write environment variables for Windows (batch file)
    if sys.platform == "win32":
        bat_file = config_dir / "env.bat"
        with open(bat_file, "w") as f:
            f.write(f"@echo off\n")
            f.write(f"REM Environment variables for {PACKAGE_NAME}\n")
            f.write(f"REM Generated during installation - version {PACKAGE_VERSION}\n\n")
            for key, value in env_vars.items():
                f.write(f'set {key}={value}\n')
        print(f"[Setup]   Windows batch file written to: {bat_file}")

    # Attempt to add to shell profile for persistence
    _append_to_shell_profile(env_file)


def _append_to_shell_profile(env_file):
    """Attempt to add source command to user's shell profile."""
    home = Path.home()
    source_line = f'\n# {PACKAGE_NAME} environment\nif [ -f "{env_file}" ]; then source "{env_file}"; fi\n'

    shell_profiles = [
        home / ".bashrc",
        home / ".zshrc",
        home / ".profile",
    ]

    for profile in shell_profiles:
        if profile.exists():
            content = profile.read_text()
            marker = f"# {PACKAGE_NAME} environment"
            if marker not in content:
                try:
                    with open(profile, "a") as f:
                        f.write(source_line)
                    print(f"[Setup]   Added source command to: {profile}")
                except PermissionError:
                    print(f"[Setup]   Warning: Could not write to {profile} (permission denied)")
            else:
                print(f"[Setup]   Source command already in: {profile}")
            break  # Only add to the first found profile


