class CleanConfigCommand(install):
    """Custom command to clean up all configuration and cached data."""

    description = "Remove all configuration directories and environment setup"

    def run(self):
        config_dir = get_config_dir()
        if config_dir.exists():
            print(f"[Cleanup] Removing configuration directory: {config_dir}")
            shutil.rmtree(config_dir)
            print("[Cleanup] Configuration directory removed successfully.")
        else:
            print("[Cleanup] No configuration directory found. Nothing to clean.")

        # Remove source lines from shell profiles
        home = Path.home()
        marker = f"# {PACKAGE_NAME} environment"
        shell_profiles = [home / ".bashrc", home / ".zshrc", home / ".profile"]

        for profile in shell_profiles:
            if profile.exists():
                lines = profile.read_text().splitlines(keepends=True)
                new_lines = []
                skip_next = False
                for line in lines:
                    if marker in line:
                        skip_next = True
                        continue
                    if skip_next:
                        skip_next = False
                        continue
                    new_lines.append(line)
                profile.write_text("".join(new_lines))
                print(f"[Cleanup] Cleaned shell profile: {profile}")


